    "P_CANCEL_MSG": "\u0647\u0644 \u062a\u0631\u064a\u062f \u0628\u0627\u0644\u062a\u0623\u0643\u064a\u062f \u0625\u0644\u063a\u0627\u0621 \u062a\u062b\u0628\u064a\u062a MyOverlay\u061f",
