    "P_SC_TITLE": "\u042f\u0440\u043b\u044b\u043a\u0438",
    "P_SC_DESC": "\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435, \u043a\u0430\u043a\u0438\u0435 \u044f\u0440\u043b\u044b\u043a\u0438 \u0441\u043e\u0437\u0434\u0430\u0442\u044c.",
    "P_SC_START": "\u0421\u043e\u0437\u0434\u0430\u0442\u044c \u044f\u0440\u043b\u044b\u043a \u0432 \u043c\u0435\u043d\u044e \u00ab\u041f\u0443\u0441\u043a\u00bb",
    "P_SC_DESKTOP": "\u0421\u043e\u0437\u0434\u0430\u0442\u044c \u0437\u043d\u0430\u0447\u043e\u043a \u043d\u0430 \u0440\u0430\u0431\u043e\u0447\u0435\u043c \u0441\u0442\u043e\u043b\u0435",
    "P_SC_NOTE": "\u042f\u0440\u043b\u044b\u043a\u0438 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u044e\u0442 MyOverlay.",
    "P_RES_TITLE": "\u0420\u0430\u0437\u0440\u0435\u0448\u0435\u043d\u0438\u0435 \u0432\u044b\u0432\u043e\u0434\u0430 \u043f\u043e \u0443\u043c\u043e\u043b\u0447\u0430\u043d\u0438\u044e",
    "P_RES_DESC": "\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435 \u0440\u0430\u0437\u0440\u0435\u0448\u0435\u043d\u0438\u0435 \u0433\u043e\u0442\u043e\u0432\u044b\u0445 \u0432\u0438\u0434\u0435\u043e \u043f\u043e \u0443\u043c\u043e\u043b\u0447\u0430\u043d\u0438\u044e.",
    "P_RES_EXPLAIN": "\u041a\u0430\u0434\u0440\u044b \u043c\u0430\u0441\u0448\u0442\u0430\u0431\u0438\u0440\u0443\u044e\u0442\u0441\u044f \u0434\u043e \u044d\u0442\u043e\u0439 \u0432\u044b\u0441\u043e\u0442\u044b \u043f\u0440\u0438 \u0440\u0435\u043d\u0434\u0435\u0440\u0438\u043d\u0433\u0435 \u043e\u0432\u0435\u0440\u043b\u0435\u044f. \u041f\u043e\u0437\u0436\u0435 \u044d\u0442\u043e \u043c\u043e\u0436\u043d\u043e \u0438\u0437\u043c\u0435\u043d\u0438\u0442\u044c \u0432 \u043d\u0430\u0441\u0442\u0440\u043e\u0439\u043a\u0430\u0445 MyOverlay.",
    "P_RES_LABEL": "\u0420\u0430\u0437\u0440\u0435\u0448\u0435\u043d\u0438\u0435:",
    "P_VR_TITLE": "\u0412\u0441\u0451 \u0433\u043e\u0442\u043e\u0432\u043e \u043a \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0435",
    "P_VR_DESC": "\u041d\u0430\u0436\u043c\u0438\u0442\u0435 \u00ab\u0423\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c\u00bb, \u0447\u0442\u043e\u0431\u044b \u043d\u0430\u0447\u0430\u0442\u044c. \u041d\u0430\u0436\u043c\u0438\u0442\u0435 \u00ab\u041d\u0430\u0437\u0430\u0434\u00bb, \u0447\u0442\u043e\u0431\u044b \u043f\u0440\u043e\u0441\u043c\u043e\u0442\u0440\u0435\u0442\u044c \u0438\u043b\u0438 \u0438\u0437\u043c\u0435\u043d\u0438\u0442\u044c \u0432\u044b\u0431\u043e\u0440, \u0438\u043b\u0438 \u00ab\u041e\u0442\u043c\u0435\u043d\u0430\u00bb, \u0447\u0442\u043e\u0431\u044b \u0432\u044b\u0439\u0442\u0438.",
    "P_VRM_TITLE": "\u0412\u0441\u0451 \u0433\u043e\u0442\u043e\u0432\u043e \u043a \u0443\u0434\u0430\u043b\u0435\u043d\u0438\u044e",
    "P_VRM_DESC": "\u041d\u0430\u0436\u043c\u0438\u0442\u0435 \u00ab\u0423\u0434\u0430\u043b\u0438\u0442\u044c\u00bb, \u0447\u0442\u043e\u0431\u044b \u0443\u0434\u0430\u043b\u0438\u0442\u044c MyOverlay \u0441 \u043a\u043e\u043c\u043f\u044c\u044e\u0442\u0435\u0440\u0430. \u041d\u0430\u0436\u043c\u0438\u0442\u0435 \u00ab\u041d\u0430\u0437\u0430\u0434\u00bb, \u0447\u0442\u043e\u0431\u044b \u043f\u0440\u043e\u0441\u043c\u043e\u0442\u0440\u0435\u0442\u044c \u0438\u043b\u0438 \u0438\u0437\u043c\u0435\u043d\u0438\u0442\u044c \u0432\u044b\u0431\u043e\u0440, \u0438\u043b\u0438 \u00ab\u041e\u0442\u043c\u0435\u043d\u0430\u00bb, \u0447\u0442\u043e\u0431\u044b \u0432\u044b\u0439\u0442\u0438.",
    "P_VRP_TITLE": "\u0412\u0441\u0451 \u0433\u043e\u0442\u043e\u0432\u043e \u043a \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u044e",
    "P_VRP_DESC": "\u041d\u0430\u0436\u043c\u0438\u0442\u0435 \u00ab\u0412\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c\u00bb, \u0447\u0442\u043e\u0431\u044b \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0443. \u041d\u0430\u0436\u043c\u0438\u0442\u0435 \u00ab\u041d\u0430\u0437\u0430\u0434\u00bb, \u0447\u0442\u043e\u0431\u044b \u0432\u0435\u0440\u043d\u0443\u0442\u044c\u0441\u044f, \u0438\u043b\u0438 \u00ab\u041e\u0442\u043c\u0435\u043d\u0430\u00bb, \u0447\u0442\u043e\u0431\u044b \u0432\u044b\u0439\u0442\u0438.",
    "P_PROG_TITLE": "\u0423\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0430 MyOverlay",
    "P_PROG_WAIT": "\u041f\u043e\u0434\u043e\u0436\u0434\u0438\u0442\u0435, \u043f\u043e\u043a\u0430 \u043c\u0430\u0441\u0442\u0435\u0440 \u0432\u044b\u043f\u043e\u043b\u043d\u044f\u0435\u0442 \u0437\u0430\u043f\u0440\u043e\u0448\u0435\u043d\u043d\u0443\u044e \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044e. \u042d\u0442\u043e \u043c\u043e\u0436\u0435\u0442 \u0437\u0430\u043d\u044f\u0442\u044c \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442.",
    "P_PROG_STATUS": "\u0421\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435:",
